import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F02_營業現金流與獲利品質_財務分析專家.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F02_營業現金流與獲利品質_財務分析專家.md"}'),l={name:"審計報告庫/財務審計/6903_巨漢/20260502/F02_營業現金流與獲利品質_財務分析專家.md"};function i(n,a,_,s,F,h){return e(),o("div",null,[...a[0]||(a[0]=[r('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>營業現金流 (CFO) 與稅後淨利 (NI) 的比值為何？自由現金流 (FCF) 是否足以支撐營運與擴張？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢 CFO 波動劇烈：2023 年 11.43 億（CFO/NI 584%）、2024 年轉負（-5.30 億）、2025 年回正至 7.80 億（CFO/NI 230%）。FCF 跟隨 CFO 波動，2024 年為 -1.89 億。現金流量品質不穩定，主因工程款收付時間差，屬工程統包業的結構性特徵。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B+（持平偏良）。2024 年 CFO 轉負為最大疑慮，但 2025 年已顯著改善。FCF 波動大，現金轉換週期長（工程款通常 60-90 天），需持續監控應收帳款週轉。利空：營收快速成長（+72.8%）未同步帶動 CFO 穩定提升，現金品質不穩定風險存在。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>CFO/NI 分析</strong>：2023 年 CFO/NI 584% 極高，主因 2023 年為上櫃前一年，多筆工程預收款入帳。2024 年轉負（-496%），因 2024 年有多筆大型工程墊款，應收帳款大幅增加。2025 年回正至 230%，但仍屬健康水準以上。整體來看，CFO/NI 波動大但多數時間 &gt;100%，獲利含金量不差。</p></li><li><p><strong>FCF 分析</strong>：2023 年 FCF 8.12 億強勁，2024 年轉負（-1.89 億），2025 年回正至 4.53 億。CapEx 支出不高（年均約 3,000-5,000 萬），FCF 波動主要來自 CFO 變動而非擴產需求。公司屬輕資產工程服務業，無需大額資本支出。</p></li><li><p><strong>營運資金壓力</strong>：工程統包業的特色——合約負債（預收款）高，但應收帳款也高。2024 年 CFO 轉負的主因是應收帳款大增（多件大型工程同時進行）。隨著工程陸續完工認列，應收帳款應可陸續回收。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>2024 年負 CFO 的後續影響</strong>：2024 年負 FCF 雖已在 2025 年回補，但若 2026 年又有大型工程啟動，同樣的現金短缺可能重演。投資人應追蹤每季 CFO 變化，判斷公司是否處於「現金消耗期」。</li><li><strong>客戶集中度風險</strong>：巨漢主要客戶為半導體大廠，單一客戶佔比可能超過 30%。若大客戶延遲付款或工程合約爭議，將直接衝擊 CFO 穩定性，應收帳款惡化風險不可忽視。</li><li><strong>成長性現金短缺警訊</strong>：營收快速成長（+72.8%）的同時若 CFO 無法同步提升，公司可能面臨「成長陷阱」——接了更多訂單但現金更緊。資金週轉壓力將壓縮獲利空間，需警惕營收擴張但現金流惡化的背離訊號。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>財務分析工具.py：cashflow_quality 6903</li><li>FinMind：TaiwanStockCashFlowsStatement（2023-2025）</li></ul>',12)])])}const C=t(l,[["render",i]]);export{c as __pageData,C as default};
